blockquote.pre:
if constexpr (is_annotation(R)) {
  return C;
} else if constexpr (is_array_type(type_of(R))) {
  return reflect_constant_array([: R :]);
} else if constexpr (is_function_type(type_of(R))) {
  return reflect_function([: R :]);
} else {
  return reflect_constant([: R :]);
}

